const filsystem = [{"question":"NTFS","answer":"Standard Windows-filsystem med støtte for ACL, kvoter, journaling og kryptering"},{"question":"ACL","answer":"Access Control List — liste over brukere/grupper og deres tillatelser på en fil eller mappe"},{"question":"Tillatelsesarv","answer":"Mekanisme i NTFS der undermapper automatisk overtar tillatelsene til overordnet mappe"},{"question":"FAT32","answer":"Eldre filsystem uten tilgangskontroll; maks filstørrelse 4 GB − 1 byte (4 294 967 295 bytes)"},{"question":"exFAT","answer":"Moderne FAT-basert filsystem uten 4 GB-begrensning; brukes på USB/SD"},{"question":"ext4","answer":"Standard Linux-filsystem med journaling, inoder og rwx-tillatelsesmodell"},{"question":"Inode","answer":"Datastruktur i Linux-filsystemer som lagrer metadata om en fil (eier, tillatelser, tidsstempel)"},{"question":"Journaling","answer":"Filsystemets transaksjonslogg som sikrer konsistens etter systemkrasj"},{"question":"Diskkvote","answer":"Grense for hvor mye lagringsplass en bruker kan bruke på et volum"},{"question":"Full kontroll","answer":"Høyeste NTFS-tillatelsesnivå — inkluderer rettigheten til å endre tillatelser og ta eierskap"},{"question":"POSIX ACL","answer":"Utvidet tilgangskontroll i Linux utover standard rwx; gir per-bruker- og per-gruppe-tillatelser med `setfacl`/`getfacl`"},{"question":"icacls","answer":"Windows kommandolinjeverktøy for å vise og endre NTFS-tillatelser"},{"question":"Share Permissions","answer":"Tillatelser som kun gjelder ved nettverkstilgang til en delt ressurs; kombineres med NTFS-tillatelser (mest restriktive gjelder)"},{"question":"EFS","answer":"Encrypting File System — NTFS-funksjonen for transparent filkryptering knyttet til brukerens sertifikat"}];
const brannmur = [{"question":"Pakkefiltrering","answer":"Stateless brannmur som inspiserer kilde/mål-IP, port og protokoll for hver pakke isolert"},{"question":"Stateful inspection","answer":"Brannmur som husker tilstanden til aktive forbindelser og tillater returtrafikk automatisk"},{"question":"WAF","answer":"Web Application Firewall – applikasjonsbrannmur som inspiserer HTTP-innhold og stopper SQL-injeksjon og XSS"},{"question":"DMZ","answer":"Demilitarisert sone – nettverk mellom internett og internt nett der internett-eksponerte servere plasseres"},{"question":"Nettverkssegmentering","answer":"Deling av nettverk i VLAN-soner med brannmurregler mellom for å begrense lateral bevegelse"},{"question":"Default-deny","answer":"Brannmurprinsipp: blokker alt, tillat kun eksplisitt godkjent trafikk"},{"question":"IDS","answer":"Intrusion Detection System – overvåker trafikk og varsler ved mistenkelig aktivitet, men blokkerer ikke"},{"question":"IPS","answer":"Intrusion Prevention System – overvåker trafikk og blokkerer automatisk mistenkelig aktivitet inline"},{"question":"Lateral bevegelse","answer":"Angriperens evne til å bevege seg mellom systemer etter å ha fått innledende tilgang"},{"question":"Vertsbasert brannmur","answer":"Brannmur som kjører på selve maskinen (f.eks. Windows Defender Firewall), i tillegg til nettverksbrannmuren"},{"question":"NGFW","answer":"Next-Generation Firewall – kombinerer stateful inspection med applikasjonsidentifisering og brukeridentitet for dypere trafikkanalyse"}];
const kryptering = [{"question":"Symmetrisk kryptering","answer":"Kryptering der samme nøkkel brukes til både kryptering og dekryptering. Rask, men nøkkeldistribusjon er utfordrende. Eks: AES-256"},{"question":"Asymmetrisk kryptering","answer":"Kryptering med nøkkelpar: offentlig nøkkel (deles fritt) og privat nøkkel (holdes hemmelig). Eks: RSA, ECC"},{"question":"Hybrid kryptering","answer":"Kombinerer asymmetrisk nøkkelutveksling med symmetrisk datakryptering – modellen TLS og HTTPS bruker"},{"question":"TLS","answer":"Transport Layer Security – protokoll som sikrer kommunikasjon over internett. TLS 1.3 er gjeldende standard"},{"question":"PKI","answer":"Public Key Infrastructure – system av sertifikater og CA-er som gjør asymmetrisk kryptering praktisk i stor skala"},{"question":"Certificate Authority (CA)","answer":"Betrodd tredjepart som utsteder og signerer digitale sertifikater, bekrefter eierskap til offentlige nøkler"},{"question":"SHA-256","answer":"Kryptografisk hashfunksjon som produserer et 256-bits fingeravtrykk. Anbefalt standard (erstatter MD5 og SHA-1)"},{"question":"Hashing","answer":"Enveisfunksjon som lager et unikt fingeravtrykk av data. Brukes til integritetskontroll og passordlagring"},{"question":"Ende-til-ende-kryptering","answer":"Kryptering der bare avsender og mottaker kan lese innholdet – ikke serveren eller tredjeparter"},{"question":"Forward secrecy","answer":"Egenskap ved TLS 1.3: selv om langtidsnøkkelen kompromitteres, kan tidligere sesjoner ikke dekrypteres"},{"question":"Salt","answer":"Tilfeldig verdi som legges til et passord før hashing for å forhindre rainbow table-angrep og gjøre identiske passord unike"},{"question":"AES-256","answer":"Advanced Encryption Standard med 256-bits nøkkel – industristandarden for symmetrisk kryptering av data i ro"}];
const personvern = [{"question":"GDPR","answer":"EUs personvernforordning (General Data Protection Regulation), gjeldende i Norge via EØS. Trådte i kraft mai 2018"},{"question":"Personopplysningsloven","answer":"Norsk lov som gjennomfører GDPR i norsk rett"},{"question":"Behandlingsgrunnlag","answer":"Juridisk grunnlag for å behandle personopplysninger (GDPR art. 6): samtykke, avtale, rettslig plikt m.fl."},{"question":"Dataminimering","answer":"Prinsipp om at kun nødvendige personopplysninger samles inn (GDPR art. 5 nr. 1 c)"},{"question":"Privacy by Design","answer":"Prinsipp om at personvern integreres i systemdesign fra starten (GDPR art. 25)"},{"question":"72-timers-regelen","answer":"Brudd med risiko for registrerte skal varsles til Datatilsynet innen 72 timer (GDPR art. 33)"},{"question":"Datatilsynet","answer":"Norsk tilsynsmyndighet for personvern. Håndhever GDPR og personopplysningsloven"},{"question":"DPO","answer":"Data Protection Officer / personvernombud – obligatorisk for offentlige organer og visse private virksomheter"},{"question":"Rett til å bli glemt","answer":"Retten til å kreve sletting av egne personopplysninger når de ikke lenger er nødvendige (GDPR art. 17)"},{"question":"Databehandleravtale","answer":"Avtale (GDPR art. 28) som regulerer hvordan en tredjepart behandler personopplysninger på vegne av virksomheten"},{"question":"Behandlingsansvarlig","answer":"Den virksomheten som bestemmer formål og midler for behandlingen av personopplysninger og har det overordnede juridiske ansvaret"},{"question":"Avvikshåndtering","answer":"Rutiner for å oppdage, stoppe og rapportere brudd på personopplysningssikkerheten til Datatilsynet og berørte"}];
const risikoanalyse = [{"question":"Risiko","answer":"Sannsynlighet multiplisert med konsekvens. Uttrykker hvor alvorlig en potensiell hendelse er"},{"question":"Risikomatrise","answer":"Visuelt verktøy (typisk 5×5) som rangerer risikoscenarioer etter sannsynlighet og konsekvens"},{"question":"Sårbarhet","answer":"En svakhet i et system som kan utnyttes av en trussel (eks. utdatert programvare, svakt passord)"},{"question":"Trussel","answer":"En potensiell hendelse som kan skade verdier i et IT-system (eks. ransomware, brann, menneskelig feil)"},{"question":"Forebyggende tiltak","answer":"Tiltak som hindrer at en hendelse inntreffer, f.eks. brannmur, MFA og patcher"},{"question":"Oppdagende tiltak","answer":"Tiltak som avslører at noe er under angrep, f.eks. logging, IDS og antivirusovervåkning"},{"question":"Reaktive tiltak","answer":"Tiltak som begrenser skaden etter en hendelse, f.eks. backup-gjenoppretting og DR-plan"},{"question":"Restrisiko","answer":"Risikoen som gjenstår etter at tiltak er innført – aksepteres formelt av ledelsen"},{"question":"GDPR art. 32","answer":"Lovkrav om å gjennomføre risikovurdering og innføre egnede sikkerhetstiltak ved behandling av personopplysninger"},{"question":"Risikoaksept","answer":"En ledelsesbeslutning om at en gjenværende risikonivå er innenfor akseptable grenser"},{"question":"ROS-analyse","answer":"Risiko- og Sårbarhetsanalyse – norsk begrep for strukturert risikovurdering, særlig brukt i offentlig sektor"},{"question":"Verdi (asset)","answer":"Alt som har verdi i en virksomhet og som bør beskyttes: data, systemer, tjenester, ansatte og omdømme"}];
const trusselbildet = [{"question":"Malware","answer":"Samlebetegnelse for ondsinnet programvare som virus, ormer, trojaner, ransomware, spyware og rootkit"},{"question":"Ransomware","answer":"Malware som krypterer filer og krever løsepenger. Dominerende trussel mot norske virksomheter (NSM)"},{"question":"Phishing","answer":"Forsøk på å lure brukere til å oppgi sensitiv informasjon ved å utgi seg for en legitim aktør"},{"question":"Spear phishing","answer":"Målrettet phishing mot én spesifikk person eller organisasjon, basert på innsamlet informasjon"},{"question":"DDoS","answer":"Distributed Denial of Service – oversvømmer en tjeneste med trafikk fra et botnet for å gjøre den utilgjengelig"},{"question":"Zero-day","answer":"Ukjent sårbarhet i programvare som utnyttes før leverandøren har utviklet en patch"},{"question":"APT","answer":"Advanced Persistent Threat – langsiktige, sofistikerte angrep fra ressurssterke (ofte statsstøttede) aktører"},{"question":"Botnet","answer":"Nettverk av kompromitterte maskiner kontrollert av en angriper, brukes bl.a. til DDoS"},{"question":"Innsidetrussel","answer":"Trussel fra ansatte eller andre med intern tilgang, enten utilsiktet (feil) eller tilsiktet (sabotasje)"},{"question":"OWASP Top 10","answer":"Liste over de ti vanligste sikkerhetsfeilene i webapplikasjoner, utgitt av OWASP"},{"question":"Pretexting","answer":"Sosial manipulering der angriperen konstruerer en troverdig falsk bakgrunnshistorie for å lure offeret"},{"question":"Smishing","answer":"SMS-phishing – svindelforsøk via tekstmelding som utgir seg for å være bank, pakkeleverandør e.l."}];
const automatisering = [{"question":"Crontab","answer":"Konfigurasjonsfil i Linux som definerer planlagte oppgaver for cron-daemonen"},{"question":"Cron-syntaks","answer":"Fem felt (min time dag mnd ukedag) etterfulgt av kommandoen som skal kjøres"},{"question":"`@reboot`","answer":"Cron-spesialstreng som kjører kommandoen ved systemoppstart"},{"question":"`crontab -e`","answer":"Kommando for å redigere brukerens crontab i standardeditoren"},{"question":"`schtasks /create`","answer":"Windows-kommandolinjeverktøy for å opprette planlagte oppgaver"},{"question":"Task Scheduler-trigger","answer":"Betingelsen som starter en oppgave (tid, hendelse, pålogging osv.)"},{"question":"Infrastructure as Code (IaC)","answer":"Praksis med å definere IT-infrastruktur i maskinlesbare konfigurasjonsfiler"},{"question":"Ansible","answer":"Agentfritt IaC-verktøy (Red Hat) som bruker YAML-playbooks via SSH"},{"question":"Terraform","answer":"Sky-agnostisk IaC-verktøy (HashiCorp) som bruker HCL for å provisjonere infrastruktur"},{"question":"Deklarativ konfigurasjon","answer":"Beskriver ønsket sluttilstand — verktøyet bestemmer selv hvilke steg som trengs"},{"question":"`2>&1`","answer":"Shell-omdirigering som sender stderr til samme sted som stdout"},{"question":"`Register-ScheduledTask`","answer":"PowerShell-cmdlet som registrerer en planlagt oppgave i Windows Task Scheduler"},{"question":"Idempotens","answer":"Prinsipp i automatisering der en operasjon kan kjøres mange ganger uten at resultatet endrer seg etter første vellykkede kjøring"},{"question":"Planlagte oppgaver","answer":"Bruk av Task Scheduler (Windows) eller cron (Linux) for å kjøre skript automatisk på gitte tidspunkter eller hendelser"},{"question":"Imperativ skripting","answer":"Skript som beskriver handlingene som skal utføres steg for steg (\"gjør A, så B\")"},{"question":"Deklarativ IaC","answer":"Konfigurasjon som beskriver ønsket sluttilstand, ikke fremgangsmåten for å nå den"}];
