  "databaseadministrasjon-en": [{"question":"Authentication","answer":"Verifies who the user is — username and password — first step in MySQL access control"},{"question":"Authorization","answer":"Determines what the authenticated user is allowed to do — second step in MySQL access control"},{"question":"GRANT","answer":"MySQL command to grant privileges to a user or role"},{"question":"REVOKE","answer":"MySQL command to remove privileges from a user or role"},{"question":"FLUSH PRIVILEGES","answer":"Forces MySQL to reload the privilege tables so changes take effect"},{"question":"mysqldump","answer":"Command-line tool for logical backup of MySQL databases — exports SQL statements"},{"question":"Logical backup","answer":"Backup stored as SQL statements (e.g., mysqldump) — portable across versions and systems"},{"question":"Index","answer":"Data structure (typically B-tree) that makes lookups in a column faster — created with CREATE INDEX"},{"question":"EXPLAIN","answer":"MySQL command that shows the query plan — used to diagnose slow queries"},{"question":"RBAC","answer":"Role-based access control — privileges are assigned to roles, roles are assigned to users"},{"question":"CREATE ROLE","answer":"MySQL 8.0 command to create a role that can group privileges"},{"question":"Full table scan","answer":"MySQL reads all rows in the table to find matches — indicated by type=ALL in EXPLAIN, avoided with indexes"},{"question":"Least privilege","answer":"Security principle — give users only the privileges they absolutely need for their task"},{"question":"Slow Query Log","answer":"MySQL feature that logs queries above a defined time threshold — used to identify performance bottlenecks"},{"question":"Indexing","answer":"Creation of a data structure that acts as a shortcut for searches and improves performance with large data volumes"}],
